const result = $input.first().json;

if (!result || result.valid !== true) {
  throw new Error('Invalid request signature');
}

return [{ json: { hmac_valid: true } }];

const session = $input.first().json;

if (!session || !session.user_id) {
  throw new Error('Invalid or expired token');
}

if (!session.user_active) {
  throw new Error('User account is inactive');
}

if (!session.client_active) {
  throw new Error('Client account is inactive');
}

return [{
  json: {
    user_id: session.user_id,
    role: session.role,
    client_id: session.client_id,
    slug: session.slug,
    name: session.name,
    email: session.email,
    message: $('Receive Chat Request').first().json.body.message,
    session_id: $('Receive Chat Request').first().json.body.session_id ?? 'no-session',
  }
}];
